// memcpy/memmove/memset have optimized implementations on some architectures
#[cfg_attr(all(feature = "arch", target_arch = "x86_64"), path = "x86_64.rs")]
mod impls;

intrinsics! {
    #[mem_builtin]
    pub unsafe extern "C" fn memcpy(dest: *mut u8, src: *const u8, n: usize) -> *mut u8 {
        impls::copy_forward(dest, src, n);
        dest
    }

    #[mem_builtin]
    pub unsafe extern "C" fn memmove(dest: *mut u8, src: *const u8, n: usize) -> *mut u8 {
        let delta = (dest as usize).wrapping_sub(src as usize);
        if delta >= n {
            // We can copy forwards because either dest is far enough ahead of src,
            // or src is ahead of dest (and delta overflowed).
            impls::copy_forward(dest, src, n);
        } else {
            impls::copy_backward(dest, src, n);
        }
        dest
    }

    #[mem_builtin]
    pub unsafe extern "C" fn memset(s: *mut u8, c: core::ffi::c_int, n: usize) -> *mut u8 {
        impls::set_bytes(s, c as u8, n);
        s
    }

    #[mem_builtin]
    pub unsafe extern "C" fn memcmp(s1: *const u8, s2: *const u8, n: usize) -> core::ffi::c_int {
        impls::compare_bytes(s1, s2, n)
    }

    #[mem_builtin]
    pub unsafe extern "C" fn bcmp(s1: *const u8, s2: *const u8, n: usize) -> core::ffi::c_int {
        memcmp(s1, s2, n)
    }

    #[mem_builtin]
    pub unsafe extern "C" fn strlen(s: *const core::ffi::c_char) -> usize {
        impls::c_string_length(s)
    }
}

use serde::Deserialize;
use std::error::Error;
use std::fmt::Write;
use std::fs;
use std::path::PathBuf;

#[derive(Deserialize, Debug)]
struct Page {
    crates: Vec<Crate>,
    meta: Meta,
}

#[derive(Deserialize, Debug)]
struct Crate {
    name: String,
    max_version: String,
}

#[derive(Deserialize, Debug)]
struct Meta {
    next_page: String,
}

pub(crate) fn fetch(output: PathBuf, number: usize) -> Result<(), Box<dyn Error>> {
    let agent = ureq::builder()
        .user_agent("clippy/lintcheck (github.com/rust-lang/rust-clippy/)")
        .build();

    let mut crates = Vec::with_capacity(number);
    let mut query = "?sort=recent-downloads&per_page=100".to_string();
    while crates.len() < number {
        let page: Page = agent
            .get(&format!("https://crates.io/api/v1/crates{query}"))
            .call()?
            .into_json()?;

        query = page.meta.next_page;
        crates.extend(page.crates);
        crates.truncate(number);

        let width = number.ilog10() as usize + 1;
        println!("Fetched {:>width$}/{number} crates", crates.len());
    }

    let mut out = "[crates]\n".to_string();
    for Crate { name, max_version } in crates {
        writeln!(out, "{name} = {{ name = '{name}', version = '{max_version}' }}").unwrap();
    }
    fs::write(output, out)?;

    Ok(())
}

